CREATE TYPE "CampaignStatus" AS ENUM ('DRAFT','SCHEDULED','PROCESSING','PAUSED','COMPLETED','CANCELED','FAILED');
CREATE TYPE "CampaignRecipientStatus" AS ENUM ('PENDING','QUEUED','SENT','DELIVERED','READ','CLICKED','FAILED','SKIPPED');
CREATE TABLE "Campaign" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"name" VARCHAR(255) NOT NULL,"description" TEXT,"status" "CampaignStatus" NOT NULL DEFAULT 'DRAFT',"whatsappAccountId" TEXT,"whatsappTemplateId" TEXT,"scheduledAt" TIMESTAMP(3),"startedAt" TIMESTAMP(3),"finishedAt" TIMESTAMP(3),"totalContacts" INTEGER NOT NULL DEFAULT 0,"totalQueued" INTEGER NOT NULL DEFAULT 0,"totalSent" INTEGER NOT NULL DEFAULT 0,"totalDelivered" INTEGER NOT NULL DEFAULT 0,"totalRead" INTEGER NOT NULL DEFAULT 0,"totalFailed" INTEGER NOT NULL DEFAULT 0,"totalClicked" INTEGER NOT NULL DEFAULT 0,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"deletedAt" TIMESTAMP(3),CONSTRAINT "Campaign_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CampaignRecipient" ("id" TEXT NOT NULL,"campaignId" TEXT NOT NULL,"leadId" TEXT,"phone" VARCHAR(32) NOT NULL,"name" VARCHAR(255),"status" "CampaignRecipientStatus" NOT NULL DEFAULT 'PENDING',"errorMessage" TEXT,"messageId" VARCHAR(255),"assignedUserId" TEXT,"queuedAt" TIMESTAMP(3),"sentAt" TIMESTAMP(3),"deliveredAt" TIMESTAMP(3),"readAt" TIMESTAMP(3),"clickedAt" TIMESTAMP(3),"failedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "CampaignRecipient_pkey" PRIMARY KEY ("id"));
CREATE INDEX "Campaign_organizationId_idx" ON "Campaign"("organizationId");
CREATE INDEX "Campaign_status_idx" ON "Campaign"("status");
CREATE INDEX "Campaign_scheduledAt_idx" ON "Campaign"("scheduledAt");
CREATE INDEX "Campaign_deletedAt_idx" ON "Campaign"("deletedAt");
CREATE INDEX "Campaign_whatsappAccountId_idx" ON "Campaign"("whatsappAccountId");
CREATE INDEX "Campaign_whatsappTemplateId_idx" ON "Campaign"("whatsappTemplateId");
CREATE INDEX "Campaign_createdById_idx" ON "Campaign"("createdById");
CREATE UNIQUE INDEX "CampaignRecipient_campaignId_leadId_key" ON "CampaignRecipient"("campaignId","leadId");
CREATE INDEX "CampaignRecipient_campaignId_idx" ON "CampaignRecipient"("campaignId");
CREATE INDEX "CampaignRecipient_leadId_idx" ON "CampaignRecipient"("leadId");
CREATE INDEX "CampaignRecipient_status_idx" ON "CampaignRecipient"("status");
CREATE INDEX "CampaignRecipient_assignedUserId_idx" ON "CampaignRecipient"("assignedUserId");
ALTER TABLE "Campaign" ADD CONSTRAINT "Campaign_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
